{
  "mode": "method",
  "tests": [
    {
      "name": "valid_create_challenge",
      "input": {
        "title": "New Challenge",
        "description": "This is a test challenge.",
        "type": "development"
      },
      "output": {
        "id": "string",
        "title": "New Challenge",
        "description": "This is a test challenge.",
        "type": "development",
        "status": "active"
      },
      "notes": "Validates that a challenge can be created successfully."
    },
    {
      "name": "valid_get_challenge",
      "input": {
        "id": "existing_challenge_id"
      },
      "output": {
        "id": "existing_challenge_id",
        "title": "Existing Challenge",
        "description": "This is an existing challenge.",
        "type": "development",
        "status": "active"
      },
      "notes": "Ensures that an existing challenge can be retrieved."
    },
    {
      "name": "invalid_create_challenge_missing_title",
      "input": {
        "description": "This is a test challenge without a title.",
        "type": "development"
      },
      "output": {
        "error": "Title is required."
      },
      "notes": "Tests the API's response to missing required fields."
    },
    {
      "name": "invalid_get_challenge_nonexistent_id",
      "input": {
        "id": "nonexistent_challenge_id"
      },
      "output": {
        "error": "Challenge not found."
      },
      "notes": "Checks the API's handling of requests for non-existent challenges."
    },
    {
      "name": "valid_update_challenge",
      "input": {
        "id": "existing_challenge_id",
        "title": "Updated Challenge Title"
      },
      "output": {
        "id": "existing_challenge_id",
        "title": "Updated Challenge Title",
        "description": "This is an existing challenge.",
        "type": "development",
        "status": "active"
      },
      "notes": "Validates that an existing challenge can be updated successfully."
    },
    {
      "name": "invalid_update_challenge_invalid_id",
      "input": {
        "id": "invalid_challenge_id",
        "title": "Updated Challenge Title"
      },
      "output": {
        "error": "Challenge not found."
      },
      "notes": "Tests the API's response to updates on non-existent challenges."
    },
    {
      "name": "valid_delete_challenge",
      "input": {
        "id": "existing_challenge_id"
      },
      "output": {
        "message": "Challenge deleted successfully."
      },
      "notes": "Validates that an existing challenge can be deleted."
    },
    {
      "name": "invalid_delete_challenge_nonexistent_id",
      "input": {
        "id": "nonexistent_challenge_id"
      },
      "output": {
        "error": "Challenge not found."
      },
      "notes": "Checks the API's handling of delete requests for non-existent challenges."
    }
  ],
  "assumptions": "All IDs used in tests are valid or invalid as specified.",
  "notes": "Ensure the database is in a known state before running tests."
}
